package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.LooncodeGroep;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.service.LooncodeGroepService;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class CachedLooncodeGroepService implements CachedService, LooncodeGroepService {

    @Autowired
    private LooncodeGroepService looncodeGroepService;

    private static final ThreadLocal<CachedLooncodeGroepBuffer> BUFFER = new ThreadLocal<>();

    private static class CachedLooncodeGroepBuffer {

        private final Map<String, LooncodeGroep> looncodeGroepBuffer = new HashMap<>();

        public LooncodeGroep get(String key) {
            return looncodeGroepBuffer.get(key);
        }

        public void put(String key, LooncodeGroep groep) {
            looncodeGroepBuffer.put(key, groep);
        }

        public void clear() {
            looncodeGroepBuffer.clear();
        }
    }

    private static CachedLooncodeGroepBuffer getBuffer() {
        CachedLooncodeGroepBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedLooncodeGroepBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    public CachedLooncodeGroepService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public LooncodeGroep getByDefineNaam(String defineNaam) {
        CachedLooncodeGroepBuffer buffer = CachedLooncodeGroepService.getBuffer();
        LooncodeGroep result = buffer.get(defineNaam);
        if (result == null) {
            result = looncodeGroepService.getByDefineNaam(defineNaam);
            buffer.put(defineNaam, result);
        }
        return result;
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public LooncodeGroep getByDefineNaamWithLooncodes(String defineNaam) {
        return looncodeGroepService.getByDefineNaamWithLooncodes(defineNaam);
    }

    @Override
    public List<LooncodeGroep> getByDefineNames(List<String> defineNames) {
        return looncodeGroepService.getByDefineNames(defineNames);
    }

    @Override
    public void clearCache() {
        CachedLooncodeGroepService.getBuffer().clear();
    }

    @Override
    public List<LooncodeGroep> findAll() {
        return looncodeGroepService.findAll();
    }

    @Override
    public LooncodeGroep create(LooncodeGroep constant) {
        return looncodeGroepService.create(constant);
    }

    @Override
    public void update(LooncodeGroep constant) {
        looncodeGroepService.update(constant);
    }

    @Override
    public void delete(LooncodeGroep constant) {
        looncodeGroepService.delete(constant);
    }

    @Override
    public LooncodeGroep getById(Integer id) {
        return looncodeGroepService.getById(id);
    }

    @Override
    public LooncodeGroep getById(Integer id, String fetchFields) {
        return looncodeGroepService.getById(id, fetchFields);
    }

    @Override
    public LooncodeGroep getByCriteria(CriteriaBuilder cb) {
        return looncodeGroepService.getByCriteria(cb);
    }


    @Override
    public List<LooncodeGroep> findAll(String fetchFields) {
        return looncodeGroepService.findAll(fetchFields);
    }

    @Override
    public List<LooncodeGroep> findByCriteria(CriteriaBuilder cb) {
        return looncodeGroepService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return looncodeGroepService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, LooncodeGroep> cacheByCriteria(CriteriaBuilder cb) {
        return looncodeGroepService.cacheByCriteria(cb);
    }

    @Override
    public LooncodeGroep getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return looncodeGroepService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<LooncodeGroep> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return looncodeGroepService.findByCriteriaTemporalFree(cb);
    }
}
